/// Lua 值类型枚举
enum FlbType {
  FLB_TNONE(-1),
  FLB_TNIL(0),
  FLB_TBOOLEAN(1),
  FLB_TLIGHTUSERDATA(2),
  FLB_TNUMBER(3),
  FLB_TSTRING(4),
  FLB_TTABLE(5),
  FLB_TFUNCTION(6),
  FLB_TUSERDATA(7),
  FLB_TTHREAD(8);

  final int value;
  const FlbType(this.value);

  static FlbType fromValue(int value) => switch (value) {
    -1 => FLB_TNONE,
    0 => FLB_TNIL,
    1 => FLB_TBOOLEAN,
    2 => FLB_TLIGHTUSERDATA,
    3 => FLB_TNUMBER,
    4 => FLB_TSTRING,
    5 => FLB_TTABLE,
    6 => FLB_TFUNCTION,
    7 => FLB_TUSERDATA,
    8 => FLB_TTHREAD,
    _ => throw ArgumentError('Unknown value for FlbType: $value'),
  };
}

